(()=>{'use strict';
const URL0='https://saodmeoilixfdqentofp.supabase.co';
const BUCKET='doit-files';
const QR_PATH='team/dev-qr.png';
const QR_CONFIG_PATH='team/dev-qr-config.json';
const $=s=>document.querySelector(s);
const T=v=>String(v??'').trim();
function cfg(){let c={};try{c=JSON.parse(localStorage.getItem('doit-cloud-cfg')||'{}')}catch{}let u=T($('#sbUrl')?.value||c.url).replace(/\/$/,'')||URL0;let k=T($('#sbKey')?.value||c.key);return{u,k}}
function H(c,x={}){return{apikey:c.k,authorization:'Bearer '+c.k,...x}}
function status(msg,ok=false){const el=$('#devQrStatus');if(el)el.innerHTML='<div class="'+(ok?'ok':'warn')+'">'+msg+'</div>';console.log('[DEV QR]',msg)}
function publicUrl(c,path){return `${c.u}/storage/v1/object/public/${BUCKET}/${path}`}
async function put(c,path,blob,type){const url=`${c.u}/storage/v1/object/${BUCKET}/${encodeURIComponent(path).replace(/%2F/g,'/')}`;const r=await fetch(url,{method:'POST',headers:H(c,{'Content-Type':type,'x-upsert':'true'}),body:blob});const t=await r.text();if(!r.ok)throw Error(t||r.status);return t}
function fileToImage(file){return new Promise((res,rej)=>{const img=new Image();img.onload=()=>res(img);img.onerror=()=>rej(Error('อ่านไฟล์ QR ไม่ได้: '+file.name));img.src=URL.createObjectURL(file)})}
function blobToDataUrl(blob){return new Promise((res,rej)=>{const fr=new FileReader();fr.onload=()=>res(fr.result);fr.onerror=rej;fr.readAsDataURL(blob)})}
async function makeQr(file){const img=await fileToImage(file);const W=900,H=900,c=document.createElement('canvas');c.width=W;c.height=H;const ctx=c.getContext('2d');ctx.fillStyle='#fff';ctx.fillRect(0,0,W,H);const pad=54,box=W-pad*2;const scale=Math.min(box/img.naturalWidth,box/img.naturalHeight);const dw=img.naturalWidth*scale,dh=img.naturalHeight*scale;ctx.drawImage(img,(W-dw)/2,(H-dh)/2,dw,dh);return await new Promise(res=>c.toBlob(res,'image/png'))}
async function preview(){const f=$('#devQrFile')?.files?.[0];if(!f)return;const blob=await makeQr(f);const data=await blobToDataUrl(blob);const img=$('#devQrPreview');if(img)img.src=data;localStorage.setItem('doit-dev-qr-preview',data)}
async function upload(){try{const c=cfg();const f=$('#devQrFile')?.files?.[0];if(!f)throw Error('ยังไม่ได้เลือกรูป QR Code');if(!c.k)throw Error('ยังไม่ได้ใส่ Supabase anon key ในช่อง Cloud / Supabase');status('กำลังปรับขนาดและอัปโหลด QR Code...');const blob=await makeQr(f);await put(c,QR_PATH,blob,'image/png');const title=T($('#devQrTitle')?.value)||'QR Code';const note=T($('#devQrNote')?.value)||'สแกนเพื่อเปิดข้อมูลเพิ่มเติม';const imgUrl=publicUrl(c,QR_PATH)+'?t='+Date.now();const config={schema:'aya-dev-qr-v1',enabled:true,title,note,image_url:imgUrl,storage_path:QR_PATH,updated_at:new Date().toISOString()};await put(c,QR_CONFIG_PATH,new Blob([JSON.stringify(config)],{type:'application/json;charset=utf-8'}),'application/json;charset=utf-8');localStorage.setItem('doit-dev-qr-config-v1',JSON.stringify(config));const img=$('#devQrPreview');if(img)img.src=imgUrl;status('อัปโหลด QR Code แล้ว<br>หน้า Pro จะแสดง QR ใต้ทีมผู้พัฒนาเมื่อเปิด popup ทีมพัฒนา',true)}catch(e){status('อัปโหลด QR Code ไม่สำเร็จ: '+(e.message||e))}}
async function disableQr(){try{const c=cfg();if(!c.k)throw Error('ยังไม่ได้ใส่ Supabase anon key ในช่อง Cloud / Supabase');const config={schema:'aya-dev-qr-v1',enabled:false,updated_at:new Date().toISOString()};await put(c,QR_CONFIG_PATH,new Blob([JSON.stringify(config)],{type:'application/json;charset=utf-8'}),'application/json;charset=utf-8');localStorage.setItem('doit-dev-qr-config-v1',JSON.stringify(config));status('ปิดการแสดง QR Code ในหน้า Pro แล้ว',true)}catch(e){status('ปิด QR ไม่สำเร็จ: '+(e.message||e))}}
function inject(){if($('#devQrAdminCard'))return;const anchor=$('#teamPhotoStatus')?.closest('.card')||$('#uploadTeamPhotos')?.closest('.card');if(!anchor)return;anchor.insertAdjacentHTML('afterend',`<section class="card" id="devQrAdminCard"><h3>อัปโหลด QR Code ใต้ทีมผู้พัฒนา</h3><p class="muted">QR Code นี้จะแสดงด้านล่างสุดใน popup ทีมผู้พัฒนาของหน้า Pro</p><div class="grid"><div class="field"><label>หัวข้อ QR</label><input id="devQrTitle" value="QR Code" placeholder="เช่น QR Code ติดต่อ / QR Code กลุ่มไลน์"></div><div class="field"><label>คำอธิบาย</label><input id="devQrNote" value="สแกนเพื่อเปิดข้อมูลเพิ่มเติม" placeholder="ข้อความใต้ QR"></div></div><div class="teamBox" style="margin-top:12px"><h4>เลือกรูป QR Code</h4><input id="devQrFile" class="teamFile" type="file" accept="image/png,image/jpeg,image/jpg,image/webp"><img id="devQrPreview" class="teamPreview" alt="Preview QR Code" style="height:220px;object-fit:contain;background:#fff"></div><div class="row" style="margin-top:12px"><button class="btn" id="uploadDevQr">อัปโหลด QR Code</button><button class="btn2 danger" id="disableDevQr">ปิดการแสดง QR</button><button class="btn2" id="openProAfterQr">เปิดหน้า Pro เพื่อตรวจ</button></div><div id="devQrStatus" class="muted" style="margin-top:10px">ยังไม่ได้เลือกรูป QR Code</div></section>`);const old=localStorage.getItem('doit-dev-qr-preview');if(old&&$('#devQrPreview'))$('#devQrPreview').src=old;$('#devQrFile')?.addEventListener('change',()=>preview().catch(e=>status(e.message||e)));$('#uploadDevQr').onclick=upload;$('#disableDevQr').onclick=disableQr;$('#openProAfterQr').onclick=()=>location.href='/pro.html?v=19&t='+Date.now()}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',inject);else inject();
})();
